import { Component, OnInit, ChangeDetectorRef } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Subject } from 'rxjs';
import { ApiService } from 'src/app/shared/services/api.service';
import { ToastService } from 'src/app/shared/services/toast.service';
import Swal from 'sweetalert2';
import { FcyDealNumberService } from './fcy-deal-number.service';

@Component({
  selector: 'npr-treasury-reference',
  templateUrl: './treasury-reference.component.html',
  styleUrls: ['./treasury-reference.component.scss']
})
export class TreasuryReferenceComponent implements OnInit {
  selectedBatchNumber: any;
  treasuryReferenceForm: FormGroup;
  dtOptions: DataTables.Settings = {};
  dtTrigger: Subject<any> = new Subject<any>();
  showTable: boolean = false;
  treasuryReferenceData: any;
  disbaleSave: boolean;
  isSelected: boolean = true;
  isLoading:boolean = false;

  constructor(private apiService: ApiService, private formBuilder: FormBuilder, 
              private toastService: ToastService, 
              private fcyService: FcyDealNumberService,
              private cdr:ChangeDetectorRef) { }

  ngOnInit(): void {
    this.treasuryReferenceForm = this.formBuilder.group({
      batch: ["", [Validators.required]],
    });
   
    this.dtOptions = {
      pagingType: 'full_numbers',
      pageLength: 5,
      processing: true,
      lengthMenu: [[5, 10, 20, -1], [5, 10, 20, 30]]
    };

    this.fetchingBatchNumber();
  }


  onSaveOfFcyDealNumber(data) {
    console.log("onSaveOfFcyDealNumber", data);
    this.fcyService.onSaveOfFcyDealNumber(data).subscribe(saveResp => {

      console.log(saveResp);
      if (saveResp) {
        Swal.fire({
          title: "Record Saved SuccessFully"

        });
        this.disbaleSave=true;
      }
      else {
        Swal.fire({
          title: "Failed Save the Record"
        })
      }
    })
  }



  fetchingBatchNumber() {
    this.isLoading = true;
    this.apiService.fetchingBatchNo().subscribe(batchNumberResp => {
      this.selectedBatchNumber = batchNumberResp;
      this.isLoading = false;
      this.cdr.markForCheck();

      this.dtTrigger.next();
      console.log("this.selectedBatchNumber", this.selectedBatchNumber);
    });
  }
  onOptionsChange(event) {
    const value = event.target.value;
    if (value) {
      this.treasuryReferenceForm.controls.batch.setValue(value);
      this.apiService.sendingBatchNumber(value).subscribe(batchResp => {
        if (batchResp == '') {
          Swal.fire(
            {
              title: "No Data for Batch:" + value,
              icon: 'warning'
            }
          );
          this.showTable = false;
        }
        else {
          this.treasuryReferenceData = batchResp;
          this.showTable = true;
        }
      });
    }
  }

  
  ngOnDestroy(): void {
    this.dtTrigger.unsubscribe();
  }

}
